#include<bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a:b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);cin.tie(0);
#define snd second
#define fst first
#define pb push_back
#define CI const int
using namespace std;
CI MAXN=2e5+5;
int a[MAXN],r[MAXN],x[MAXN],t[MAXN];
queue<int> d[MAXN];
priority_queue<PII,vector<PII>,greater<PII>>s;
int n,m,ans;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)
		{
			ans=ans*a;
		}
		a=a*a;
		b>>=1;
	}
	return ans;
}
void solve()
{
	cin>>n>>m;
	wh(!s.empty())
	{
		s.pop();
	}
	FOR(i,1,n)
	{
		cin>>a[i];
		r[i]=a[i];
		wh(!d[i].empty())
		{
			d[i].pop();
		}
	}
	FOR(i,1,m)
	{
		cin>>x[i]>>t[i];
		d[t[i]].push(x[i]);
	}
	FOR(i,1,n)
	{
		d[i].push(inf);
	}
	FOR(i,1,n)
	{
		int f=d[i].front();
		d[i].pop();
		s.push(mk(f,i));
	}
	ans=0;
	FOR(i,1,m)
	{
		int len=x[i]-x[i-1];
		wh(len>0)
		{
			if(s.empty())
			{
				break;
			}
			PII top=s.top();
			s.pop();
			if(a[top.snd]==0)
			{
				continue;
			}
			if(a[top.snd]<=len)
			{
				len-=a[top.snd];
				a[top.snd]=0;
			}
			else
			{
				a[top.snd]-=len;
				len=0;
				s.push(top);
				break;
			}
		}
		if(len>0)
		{
			ans+=x[i]-x[i-1]-len;
			break;
		}
		else
		{
			a[t[i]]=r[t[i]];
			int fi=inf,se=t[i];
			if(!d[se].empty())
			{
				fi=d[se].front();
				d[se].pop();
			}
			if(!s.empty())
			{
				if(s.top().snd==se)
				{
					s.pop();
				}
			}
			s.push(mk(fi,se));
			ans+=x[i]-x[i-1];
		}
	}
	FOR(i,1,n)
	{
		ans+=a[i];
	}
	cout<<ans<<'\n';
}
signed main(void)
{
	IOS
	int T;
	cin>>T;
	wh(T--)
	{
		solve();
	}
	return false;
}
